            builder.Append("HalfHourNetChange=");
            builder.Append(this.HalfHourNetChange);
            builder.Append('|');
            builder.Append("QuarterHourNetChange=");
            builder.Append(this.QuarterHourNetChange);
            builder.Append('|');
            builder.Append("Last=");
            builder.Append(this.Last);

            this.Limit = originalLimit;

        }
    }
}
